sql:
SELECT DISTINCT ec.cycle_name
FROM model_performance mp
JOIN election_cycles ec ON mp.cycle_id = ec.cycle_id;

SELECT COUNT(*) AS race_count
FROM races
WHERE cycle_id = (SELECT cycle_id FROM election_cycles WHERE cycle_name = '2018 Midterm Elections');

external_knowledge:
- "most skilled" refers to having the highest average rating;
- "busiest" refers to having conducted the largest number of polls;
- "most recent polls" refers to polls with the maximum date for each race.

sql:
SELECT pollster_name, rating
FROM pollster_ratings
ORDER BY rating DESC;

SELECT cycle_name
FROM election_cycles
WHERE cycle_id = 1;
